func:
const p = msg.topic.split('/');
if (p.length < 5) return null;
const serial = p[3];
const d = msg.payload || {};
const infoMap = global.get('info_map') || {};

infoMap[serial] = {
    type:             d.device_type || d.type || '',
    production_date:  d.production_date || '',
    hw_version:       d.hw_version || 0,
    serial_number:    d.serial_number || serial
};

global.set('info_map', infoMap);
return null;

const p = msg.topic.split('/');
const serial = p[3];
const d = msg.payload || {};
const settingsMap = global.get('settings_cache') || {};

function pick(camel, snake) { return d[camel] !== undefined ? d[camel] : d[snake]; }

settingsMap[serial] = {
    serial:                      d.serial               || serial,
    battery_type_index:          pick('batteryTypeIndex',         'battery_type_index')         || 0,
    capacity_ah:                 pick('capacityAh',               'capacity_ah')                || 100,
    lvd_voltage_mv:              pick('lvdVoltageMv',             'lvd_voltage_mv')             || 11000,
    lvd_mode_voltage:            pick('lvdModeVoltage',           'lvd_mode_voltage')           || false,
    night_mode_index:            pick('nightModeIndex',           'night_mode_index')           || 1,
    evening_minutes_mn:          pick('eveningMinutesMn',         'evening_minutes_mn')         || 0,
    morning_minutes_mn:          pick('morningMinutesMn',         'morning_minutes_mn')         || 0,
    night_threshold_mv:          pick('nightThresholdMv',         'night_threshold_mv')         || 11500,
    night_mode_dimming_index:    pick('nightModeDimmingIndex',    'night_mode_dimming_index')   || 0,
    evening_minutes_dimming_mn:  pick('eveningMinutesDimmingMn',  'evening_minutes_dimming_mn') || 0,
    morning_minutes_dimming_mn:  pick('morningMinutesDimmingMn',  'morning_minutes_dimming_mn') || 0,
    dimming_pct:                 pick('dimmingPct',               'dimming_pct')                || 100,
    base_dimming_pct:            pick('baseDimmingPct',           'base_dimming_pct')           || 30,
    dali_power_enable:           pick('daliPowerEnable',          'dali_power_enable')          || false,
    alc_dimming_enable:          pick('alcDimmingEnable',         'alc_dimming_enable')         || false
};
global.set('settings_cache', settingsMap);

// Output 0: re-trigger device select if this is the currently selected device
// Output 1: always refresh dropdown options
const selected = flow.get('selected_serial');
const repopulate = (selected === serial) ? { payload: serial } : null;
return [repopulate, {}];

const p = msg.topic.split('/');
const serial = p[3];
const zone = p[1];
const isOnline = msg.payload.toString().trim() === '1';
const key = 'online_' + serial;
const wasOnline = context.get(key);
context.set(key, isOnline);

const onlineMap = global.get('online_map') || {};
onlineMap[serial] = { online: isOnline, ts: new Date().toISOString() };
global.set('online_map', onlineMap);

if (!isOnline && wasOnline !== false) {
    const ts = new Date().toISOString();
    return [{ payload: {
        severity: 'critical', condition: 'Device offline',
        emailNeeded: true, serial, zone, ts,
        subject: '[MPPT CRITICAL] ' + serial + ' offline',
        body: 'Device ' + serial + ' (zone: ' + zone + ') went offline at ' + ts
    }}];
}
if (isOnline && wasOnline === false) {
    node.log(serial + ' back online');
}
return null;

if (!msg.payload || !msg.payload.subject) return null;
msg.topic = msg.payload.subject;
msg.payload = msg.payload.body;
return msg;

const p = msg.topic.split('/');
if (p.length < 5) return null;
msg.zone       = p[1];
msg.gateway_id = p[2];
msg.serial     = p[3];

const d = msg.payload || {};

const infoMap = global.get('info_map') || {};
const info    = infoMap[msg.serial] || {};

msg.gen = {
    hw_version:         d.hw_version         || info.hw_version || 0,
    serial_number:      d.serial             || info.serial_number || msg.serial,
    firmware_version:   d.firmware_version   || 0,
    internal_temp_c:    d.internal_temp_c    || 0,
    external_temp_c:    d.external_temp_c    || 0,
    controller_op_days: d.controller_op_days || 0,
    timestamp:          new Date().toISOString()
};

msg.bat = {
    voltage_v:               d.battery_voltage_v       || 0,
    soc_pct:                 d.battery_soc_pct         || 0,
    charge_current_a:        d.charge_current_a        || 0,
    charge_power_w:          d.charge_power_w          || 0,
    end_of_charge_voltage_v: d.end_of_charge_voltage_v || 0,
    charge_mode:             d.charge_mode             || 'unknown',
    is_night:                !!d.is_night,
    bat_op_days:             d.bat_op_days             || 0,
    energy_in_daily_wh:      d.energy_in_daily_wh      || 0,
    energy_out_daily_wh:     d.energy_out_daily_wh     || 0,
    energy_retained_wh:      d.energy_retained_wh      || 0,
    detected:                !!d.battery_detected
};

msg.load = {
    load_on:        !!d.load_on,
    night_mode:     !!d.night_mode,
    lvd_active:     !!d.lvd_active,
    user_disconnect:!!d.user_disconnect,
    over_current:   !!d.over_current,
    current_a:      d.load_current_a || 0,
    power_w:        d.load_power_w   || 0
};

msg.pv = {
    voltage_v:        d.pv_voltage_v        || 0,
    target_voltage_v: d.pv_target_voltage_v || 0,
    detected:         !!d.pv_detected
};

msg.night = {
    time_since_dusk_min: d.time_since_dusk_min || 0,
    average_length_min:  d.average_length_min  || 0
};

msg.led = {
    voltage_v:   d.led_voltage_v || 0,
    current_a:   d.led_current_a || 0,
    power_w:     d.led_power_w   || 0,
    status:      d.led_status    || 'Normal',
    dali_active: !!d.dali_active
};

msg.faults = {
    battery_over_voltage:   !!d.fault_battery_over_voltage,
    pv_over_voltage:        !!d.fault_pv_over_voltage,
    controller_over_temp:   !!d.fault_controller_over_temp,
    charge_over_current:    !!d.fault_charge_over_current,
    lvd_active:             !!d.fault_lvd_active,
    over_discharge_current: !!d.fault_over_discharge_current,
    load_over_current:      !!d.fault_load_over_current,
    battery_over_temp:      !!d.fault_battery_over_temp,
    battery_under_temp:     !!d.fault_battery_under_temp
};

msg.hw_version = String(msg.gen.hw_version);

const fleet = global.get('fleet') || {};
fleet[msg.serial] = {
    serial: msg.serial, zone: msg.zone, gateway_id: msg.gateway_id,
    hw_version: msg.hw_version,
    bat: msg.bat, load: msg.load, pv: msg.pv, faults: msg.faults,
    gen: msg.gen, ts: msg.gen.timestamp
};
global.set('fleet', fleet);
return msg;

const bat = msg.bat, load = msg.load, faults = msg.faults;
const serial = msg.serial, zone = msg.zone;
const ts = msg.gen.timestamp || new Date().toISOString();

const checks = [
    { cond: bat.soc_pct >= 10 && bat.soc_pct < 20, sev: 'warning',  email: false,
      msg: 'Battery SOC low (' + bat.soc_pct + '%)' },
    { cond: bat.soc_pct < 10,                       sev: 'critical', email: true,
      msg: 'Battery SOC critical (' + bat.soc_pct + '%)' },
    { cond: !!(faults.lvd_active || load.lvd_active), sev: 'critical', email: true,
      msg: 'LVD active' },
    { cond: !!faults.battery_over_voltage,  sev: 'critical', email: true, msg: 'Battery over voltage' },
    { cond: !!faults.over_discharge_current,sev: 'critical', email: true, msg: 'Over discharge current' },
    { cond: !!faults.battery_over_temp,     sev: 'critical', email: true, msg: 'Battery over temperature' },
    { cond: !!faults.battery_under_temp,    sev: 'critical', email: true, msg: 'Battery under temperature' },
];

const out = checks.filter(c => c.cond).map(c => ({ payload: {
    severity: c.sev, condition: c.msg, emailNeeded: c.email,
    serial, zone, ts,
    subject: '[MPPT ' + c.sev.toUpperCase() + '] ' + serial + ' - ' + c.msg,
    body: 'Device: ' + serial + '\nZone: ' + zone + '\nCondition: ' + c.msg + '\nTimestamp: ' + ts
}}));

if (!out.length) return null;
const email = out.filter(m => m.payload.emailNeeded);
return [ email.length ? email : null, out ];

const num = (v, d=0) => typeof v === 'number' ? v : d;
const tags = {
    zone: msg.zone, gateway_id: msg.gateway_id, serial: msg.serial,
    hw_version: msg.hw_version || '0',
    charge_mode: msg.bat.charge_mode || 'unknown'
};
const fields = {
    voltage_v:           num(msg.bat.voltage_v),
    soc_pct:             num(msg.bat.soc_pct),
    charge_current_a:    num(msg.bat.charge_current_a),
    charge_power_w:      num(msg.bat.charge_power_w),
    is_night:            msg.bat.is_night ? 1 : 0,
    energy_in_daily_wh:  num(msg.bat.energy_in_daily_wh),
    energy_out_daily_wh: num(msg.bat.energy_out_daily_wh),
    energy_retained_wh:  num(msg.bat.energy_retained_wh),
    load_on:             msg.load.load_on ? 1 : 0,
    lvd_active:          (msg.load.lvd_active || msg.faults.lvd_active) ? 1 : 0,
    load_current_a:      num(msg.load.current_a),
    load_power_w:        num(msg.load.power_w),
    pv_voltage_v:        num(msg.pv.voltage_v),
    pv_target_voltage_v: num(msg.pv.target_voltage_v),
    internal_temp_c:     num(msg.gen.internal_temp_c),
    external_temp_c:     num(msg.gen.external_temp_c),
    led_voltage_v:       num(msg.led.voltage_v),
    led_current_a:       num(msg.led.current_a),
    led_power_w:         num(msg.led.power_w)
};
msg.payload = [fields, tags];
return msg;

const num = (v, d=0) => typeof v === 'number' ? v : d;
const f = msg.faults || {}, load = msg.load || {};
const any = !!(f.battery_over_voltage || f.pv_over_voltage || f.controller_over_temp ||
    f.charge_over_current || f.lvd_active || f.over_discharge_current ||
    f.load_over_current || f.battery_over_temp || f.battery_under_temp ||
    load.lvd_active || load.over_current);
const tags = {
    zone: msg.zone, gateway_id: msg.gateway_id,
    serial: msg.serial, hw_version: msg.hw_version || '0'
};
const fields = {
    battery_over_voltage:   f.battery_over_voltage   ? 1 : 0,
    pv_over_voltage:        f.pv_over_voltage         ? 1 : 0,
    controller_over_temp:   f.controller_over_temp    ? 1 : 0,
    charge_over_current:    f.charge_over_current     ? 1 : 0,
    lvd_active:             (f.lvd_active || load.lvd_active) ? 1 : 0,
    over_discharge_current: f.over_discharge_current  ? 1 : 0,
    load_over_current:      (f.load_over_current || load.over_current) ? 1 : 0,
    battery_over_temp:      f.battery_over_temp       ? 1 : 0,
    battery_under_temp:     f.battery_under_temp      ? 1 : 0,
    any_fault:              any ? 1 : 0
};
msg.payload = [fields, tags];
return msg;

const p = msg.topic.split('/');
if (p.length < 5) return null;
const zone = p[1], gateway = p[2], serial = p[3];

// Proto DataloggerPayload is the root object — no .datalogger wrapper.
const dl = msg.payload;
if (!dl || typeof dl !== 'object') return null;

const num = v => (typeof v === 'number' ? v : 0);
const bool01 = v => (v ? 1 : 0);

const infoMap    = global.get('info_map') || {};
const info       = infoMap[serial] || {};
const hw_version = String(info.hw_version || dl.hw_version || 0);
const ct         = { serial, gateway_id: gateway, zone, hw_version };

// Summary
const summary = [{ measurement: 'datalogger_summary', payload: [{
    recorded_days:              num(dl.recorded_days),
    days_with_lvd:              num(dl.days_with_lvd),
    months_without_full_charge: num(dl.months_without_full_charge),
    avg_morning_soc_pct:        num(dl.avg_morning_soc_pct),
    total_ah_charge:            num(dl.total_ah_charge),
    total_ah_load:              num(dl.total_ah_load)
}, ct]}];

// Daily logs — proto uses daily_logs[i].index (not .day)
const daily = [];
const dailyArr = Array.isArray(dl.daily_logs) ? dl.daily_logs : [];
dailyArr.forEach((d, i) => {
    daily.push({ measurement: 'datalogger_daily', payload: [{
        day_num:         num(d.index),
        vbat_min_v:      num(d.vbat_min_v),  vbat_max_v:      num(d.vbat_max_v),
        vpv_min_v:       num(d.vpv_min_v),   vpv_max_v:        num(d.vpv_max_v),
        ah_charge:       num(d.ah_charge),   ah_load:          num(d.ah_load),
        soc_pct:         num(d.soc_pct),
        ext_temp_max_c:  num(d.ext_temp_max_c), ext_temp_min_c: num(d.ext_temp_min_c),
        nightlength_min: num(d.nightlength_min),
        il_max_a:        num(d.il_max_a),    ipv_max_a:        num(d.ipv_max_a),
        flag_load_disconnect:   bool01(d.flag_load_disconnect),
        flag_full_charge:       bool01(d.flag_full_charge),
        flag_pv_over_current:   bool01(d.flag_pv_over_current),
        flag_load_over_current: bool01(d.flag_load_over_current),
        flag_bat_over_voltage:  bool01(d.flag_battery_over_voltage),
        flag_low_soc:           bool01(d.flag_low_soc)
    }, Object.assign({ day_index: String(i + 1) }, ct)]});
});

// Monthly logs — proto uses monthly_logs[i].index (not .month)
const monthly = [];
const monthlyArr = Array.isArray(dl.monthly_logs) ? dl.monthly_logs : [];
monthlyArr.forEach((m, i) => {
    monthly.push({ measurement: 'datalogger_monthly', payload: [{
        month_num:       num(m.index),
        vbat_min_v:      num(m.vbat_min_v),  vbat_max_v:      num(m.vbat_max_v),
        vpv_min_v:       num(m.vpv_min_v),   vpv_max_v:        num(m.vpv_max_v),
        ah_charge:       num(m.ah_charge),   ah_load:          num(m.ah_load),
        soc_pct:         num(m.soc_pct),
        ext_temp_max_c:  num(m.ext_temp_max_c), ext_temp_min_c: num(m.ext_temp_min_c),
        nightlength_min: num(m.nightlength_min),
        il_max_a:        num(m.il_max_a),    ipv_max_a:        num(m.ipv_max_a)
    }, Object.assign({ month_index: String(i + 1) }, ct)]});
});

return [
    summary.length ? summary : null,
    daily.length   ? daily   : null,
    monthly.length ? monthly : null
];

const fleet = global.get('fleet') || {};
const onlineMap = global.get('online_map') || {};
const serials = Object.keys(fleet).sort();

if (!serials.length) {
    const empty = '<p style="color:#94a3b8;padding:24px;text-align:center;font-style:italic">No devices detected on the network yet.</p>';
    return [{ payload: empty }, { payload: empty }];
}

let totalDevices = serials.length;
let onlineCount = 0;
let faultCount = 0;
let totalSoc = 0;
let totalCharge = 0;

for (const s of serials) {
    const d = fleet[s];
    const om = onlineMap[s];
    if (!om || om.online) onlineCount++;
    if (d.faults && (d.faults.any_fault || Object.values(d.faults).some(v => v === 1 || v === true))) faultCount++;
    totalSoc += (d.bat && typeof d.bat.soc_pct === 'number') ? d.bat.soc_pct : 0;
    totalCharge += (d.bat && typeof d.bat.charge_power_w === 'number') ? d.bat.charge_power_w : 0;
}

const avgSoc = totalDevices ? Math.round(totalSoc / totalDevices) : 0;
const offlineCount = totalDevices - onlineCount;

function statCard(label, value, sub, color) {
    return '<div style="display:flex; flex-direction:column; align-items:center; justify-content:center; background:rgba(30, 41, 59, 0.7); border:1px solid #334155; border-radius:12px; padding:20px; margin:8px; min-width:160px; flex:1; box-shadow:0 4px 6px -1px rgb(0 0 0 / 0.1)">' +
        '<div style="font-size:32px; font-weight:800; color:' + color + '; line-height:1">' + value + '</div>' +
        '<div style="font-size:13px; font-weight:600; color:#94a3b8; margin-top:8px; text-transform:uppercase; letter-spacing:0.05em">' + label + '</div>' +
        (sub ? '<div style="font-size:11px; color:#64748b; margin-top:2px">' + sub + '</div>' : '') +
        '</div>';
}

const summaryHtml = '<div style="display:flex; flex-wrap:wrap; justify-content:space-between; width:100%">' +
    statCard('Devices', totalDevices, 'total', '#3b82f6') +
    statCard('Online', onlineCount, offlineCount + ' offline', onlineCount === totalDevices ? '#22c55e' : '#f59e0b') +
    statCard('Avg SOC', avgSoc + '%', '', avgSoc > 50 ? '#22c55e' : avgSoc > 20 ? '#f59e0b' : '#ef4444') +
    statCard('Charge', Math.round(totalCharge) + ' W', 'fleet total', '#3b82f6') +
    statCard('Faults', faultCount, faultCount ? 'devices with issues' : 'all clear', faultCount ? '#ef4444' : '#22c55e') +
    '</div>';

let rows = '';
for (const s of serials) {
    const d = fleet[s];
    const om = onlineMap[s] || { online: true };
    const online = om.online;
    const soc = (d.bat && d.bat.soc_pct) || 0;
    const vbat = (d.bat && d.bat.voltage_v) || 0;
    const icharge = (d.bat && d.bat.charge_current_a) || 0;
    const iload = (d.load && d.load.current_a) || 0;
    const faults = d.faults && (d.faults.any_fault || Object.values(d.faults).some(v => v === 1 || v === true));

    rows += '<tr style="border-bottom:1px solid #334155">' +
        '<td style="padding:12px 8px"><div style="display:flex; align-items:center"><div style="width:8px; height:8px; border-radius:50%; background:' + (online ? '#22c55e' : '#ef4444') + '; margin-right:10px"></div>' +
        '<div><div style="font-weight:600; color:#f1f5f9">' + s + '</div><div style="font-size:10px; color:#64748b">' + (d.zone || 'N/A') + ' / ' + (d.gateway_id || 'N/A') + '</div></div></div></td>' +
        '<td style="padding:12px 8px; text-align:center"><div style="width:100%; background:#334155; height:6px; border-radius:3px; margin-bottom:4px">' +
        '<div style="width:' + soc + '%; background:' + (soc > 50 ? '#22c55e' : soc > 20 ? '#f59e0b' : '#ef4444') + '; height:100%; border-radius:3px"></div></div>' +
        '<span style="font-size:12px; font-weight:700; color:#f1f5f9">' + soc + '%</span></td>' +
        '<td style="padding:12px 8px; text-align:center; color:#f1f5f9">' + vbat.toFixed(1) + 'V</td>' +
        '<td style="padding:12px 8px; text-align:center; color:#3b82f6; font-weight:600">' + icharge.toFixed(1) + 'A</td>' +
        '<td style="padding:12px 8px; text-align:center; color:#f59e0b; font-weight:600">' + iload.toFixed(1) + 'A</td>' +
        '<td style="padding:12px 8px; text-align:center">' + (faults ? '<span style="background:#ef4444; color:white; padding:2px 6px; border-radius:4px; font-size:10px; font-weight:800">FAULT</span>' : '<span style="color:#22c55e; font-size:18px">✓</span>') + '</td></tr>';
}

const tableHtml = '<table style="width:100%; border-collapse:collapse; color:#94a3b8; font-size:13px"><thead><tr style="text-align:left; border-bottom:2px solid #334155">' +
    '<th style="padding:8px; font-weight:600; color:#cbd5e1">Device / Zone</th>' +
    '<th style="padding:8px; text-align:center; font-weight:600; color:#cbd5e1">SOC</th>' +
    '<th style="padding:8px; text-align:center; font-weight:600; color:#cbd5e1">Bat V</th>' +
    '<th style="padding:8px; text-align:center; font-weight:600; color:#cbd5e1">Charge</th>' +
    '<th style="padding:8px; text-align:center; font-weight:600; color:#cbd5e1">Load</th>' +
    '<th style="padding:8px; text-align:center; font-weight:600; color:#cbd5e1">Status</th></tr></thead><tbody>' + rows + '</tbody></table>';

return [{ payload: summaryHtml }, { payload: tableHtml }];

const serial = msg.payload;
const out = new Array(18).fill(null);

if (!serial || typeof serial !== 'string') {
    flow.set('selected_serial', null);
    out[0] = { payload: `<div style="padding:60px 20px;text-align:center;color:#64748b;font-size:15px;">Select a device from the dropdown above</div>` };
    out[17] = { payload: '' };
    node.send(out);
    return null;
}

flow.set('selected_serial', serial);
flow.set('w__dirty', false);

const fleet = global.get('fleet') || {};
const onlineMap = global.get('online_map') || {};
const settingsMap = global.get('settings_cache') || {};
const infoMap = global.get('info_map') || {};

const dev = fleet[serial] || {};
const s = settingsMap[serial] || null;
const info = infoMap[serial] || {};
const online = onlineMap[serial] ? onlineMap[serial].online !== false : true;

// ==================== DEVICE INFO ====================
const statusColor = online ? '#22c55e' : '#ef4444';
out[0] = { payload: `
<div style="background:#1e2937;padding:18px;border-radius:8px;margin-bottom:16px;">
    <div style="display:flex;align-items:center;gap:12px;margin-bottom:14px;">
        <div style="width:16px;height:16px;border-radius:50%;background:${statusColor};"></div>
        <span style="font-size:26px;font-weight:700;">${serial}</span>
        <span style="color:${statusColor};font-weight:700;">${online ? '● ONLINE' : '○ OFFLINE'}</span>
    </div>

    <div style="display:grid;grid-template-columns:120px 1fr;gap:8px;font-size:14.5px;line-height:1.6;">
        <div style="color:#64748b;">Model</div>     <div style="color:#e2e8f0;">${info.type || 'Phocos MPPT'} V${info.hw_version || '?'}</div>
        <div style="color:#64748b;">Produced</div>  <div style="color:#e2e8f0;">${info.production_date || '—'}</div>
        <div style="color:#64748b;">Zone</div>      <div style="color:#e2e8f0;">${dev.zone || 'default'}</div>
        <div style="color:#64748b;">Gateway</div>   <div style="color:#e2e8f0;">${dev.gateway_id || '—'}</div>
    </div>
</div>` };

// ==================== DEVICE CONFIG ====================
const BAT = ['AGM','Liquid','LiFePO4 High Temp','LiFePO4 Med Temp','LiFePO4 Low Temp'];
const MODE = ['Off','D2D','DD','MN'];

let cfg = s ? `
<div style="background:#1e2937;padding:18px;border-radius:8px;">
    <div style="font-size:15px;font-weight:700;color:#e2e8f0;margin-bottom:16px;">DEVICE CONFIGURATION</div>

    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px 30px;font-size:14.5px;">
        <div><span style="color:#64748b;">Battery Type</span><br><strong>${BAT[s.battery_type_index]||s.battery_type_index}</strong></div>
        <div><span style="color:#64748b;">Capacity</span><br><strong>${s.capacity_ah} Ah</strong></div>
        <div><span style="color:#64748b;">LVD</span><br><strong>${(s.lvd_voltage_mv/1000).toFixed(1)} V</strong></div>
