    let v = flow.get('w_w-' + key);
    if (v === undefined || v === null) return cacheVal;

    // Force coercion to match cache type to prevent string/bool traps
    if (typeof cacheVal === 'boolean') return (v === true || v === 'true');
    if (typeof cacheVal === 'number') return Number(v);
    return v;
};

